example.code:
# /etc/logstash/conf.d/main.conf

input {
  beats {
    port => 5044
    ssl => true
    ssl_certificate => "/etc/logstash/certs/logstash.crt"
    ssl_key         => "/etc/logstash/certs/logstash.key"
  }
}

filter {
  # Parse JSON logs
  if [message] =~ /^\{/ {
    json {
      source => "message"
      target => "parsed"
    }
    mutate {
      rename => { "[parsed][level]" => "level" }
      rename => { "[parsed][msg]"   => "log_message" }
    }
  }

  # Parse timestamp
  date {
    match  => ["[parsed][timestamp]", "ISO8601", "yyyy-MM-dd HH:mm:ss"]
    target => "@timestamp"
  }

  # Add environment tag
  mutate {
    add_field    => { "environment" => "production" }
    remove_field => ["agent", "ecs", "input"]
  }
}

output {
  elasticsearch {
    hosts    => ["https://elasticsearch:9200"]
    index    => "logs-%{[service]}-%{+YYYY.MM.dd}"
    user     => "logstash"
    password => "${LOGSTASH_PASSWORD}"
    ssl_certificate_verification => true
    cacert   => "/etc/logstash/certs/ca.crt"
  }
}

filter {
  # Parse different log formats per service
  if [service] == "nginx" {
    grok {
      match => {
        "message" => '%{IPORHOST:client_ip} - %{DATA:user} \[%{HTTPDATE:timestamp}\] "%{WORD:method} %{DATA:request} HTTP/%{NUMBER:http_version}" %{NUMBER:status} %{NUMBER:bytes} "%{DATA:referrer}" "%{DATA:user_agent}"'
      }
    }
  } else if [service] == "application" {
    json { source => "message" }
  }

  # Enrich with GeoIP
  if [client_ip] {
    geoip {
      source => "client_ip"
      target => "geo"
      fields => ["country_name", "city_name", "location"]
    }
  }

  # Parse user agent
  if [user_agent] {
    useragent {
      source => "user_agent"
      target => "ua"
    }
  }

  # Mask sensitive data (PII / secrets)
  mutate {
    gsub => [
      "message", "password=\\S+",    "password=[REDACTED]",
      "message", "\\b\\d{16}\\b",    "[CARD_REDACTED]",
      "message", "Bearer\\s+\\S+",   "Bearer [REDACTED]"
    ]
  }

  # Normalize log levels
  mutate { uppercase => ["level"] }
  translate {
    field       => "level"
    destination => "level"
    override    => true
    dictionary  => {
      "WARN"  => "WARNING"
      "FATAL" => "CRITICAL"
    }
  }

  # Categorize response time
  if [duration_ms] {
    if [duration_ms] < 100 {
      mutate { add_field => { "response_category" => "fast" } }
    } else if [duration_ms] < 1000 {
      mutate { add_field => { "response_category" => "normal" } }
    } else {
      mutate { add_field => { "response_category" => "slow" } }
    }
  }
}

output {
  elasticsearch {
    hosts    => ["https://elasticsearch:9200"]
    index    => "logs-%{+YYYY.MM.dd}"
    user     => "logstash"
    password => "${LOGSTASH_PASSWORD}"
  }

  # Capture failed events separately
  if "_grokparsefailure" in [tags] or "_jsonparsefailure" in [tags] {
    file {
      path  => "/var/log/logstash/failed/%{+YYYY-MM-dd}.json"
      codec => json_lines
    }
  }
}
